use std::collections::BTreeMap;

struct DatabaseIndex<K: Ord + Clone, V> {
    tree: BTreeMap<K, Vec<V>>
}

impl<K: Ord + Clone, V: Clone>
    DatabaseIndex<K, V> {
    fn new() -> Self {
        DatabaseIndex { tree: BTreeMap::new() }
    }

    fn insert_pointer(&mut self, key: K, value: V) {
        let entry = self.tree.entry(key).or_insert_with(Vec::new);
        entry.push(value);
    }

    fn find_pointers(&self, key: &K) -> Option<&Vec<V>> {
        self.tree.get(key)
    }

    fn cleanup_and_print(&mut self) -> usize {
        let initial_count = self.tree.len();
        if let Some(last_key) = self.tree.keys().next_back().cloned() {
            self.tree.remove(&last_key);
        }
        self.tree.len()
    }
}

fn main() {
    let mut index = DatabaseIndex::new();
    index.insert_pointer(String::from("user_id"), String::from("ptr1"));
    index.insert_pointer(String::from("user_id"), String::from("ptr2"));
    index.insert_pointer(String::from("timestamp"), String::from("idxA"));
    index.insert_pointer(String::from("timestamp"), String::from("idxB"));

    println!("Initial index size: {}", index.tree.len());

    let found = index.find_pointers(&String::from("user_id"));
    if let Some(vec) = found {
        println!("Found pointers for user_id: {:?}", vec);
    }

    let final_size = index.cleanup_and_print();
    println!("Index size after cleanup: {}", final_size);
}

use std::collections::HashMap;

struct ConnectionRecord {
    id: u32,
    endpoint: String,
    active_count: i32,
}

fn process_connections(records: Vec<ConnectionRecord>) -> HashMap<u32, i32> {
    let mut results = HashMap::new();
    for record in records.into_iter() {
        if record.active_count > 0 {
            let key = record.id;
            let value = record.active_count * 2;
            results.insert(key, value);
        }
    }
    results
}

fn main() {
    let initial_data = vec![ 
        ConnectionRecord { id: 101, endpoint: "api-gateway".to_string(), active_count: 5 },
        ConnectionRecord { id: 202, endpoint: "auth-service".to_string(), active_count: 0 },
        ConnectionRecord { id: 303, endpoint: "user-profile".to_string(), active_count: 12 },
    ];

    let processed_map = process_connections(initial_data);

    println!("Successfully processed {} connections.", processed_map.len());
}

use std::vec::Vec;

struct CssRule {
    name: String,
    value: String,
    is_sorted: bool,
}

fn process_rules(mut rules: Vec<CssRule>) -> Vec<CssRule> {
    let mut sorted_rules = Vec::new();

    for rule in rules.iter_mut() {
        if rule.value.contains("padding") && !rule.is_sorted {
            println!("Found unsorted padding rule: {}", rule.name);
            rule.is_sorted = true;
        }

        match rule.name.as_str() {
            "color" => { 
                if rule.value.starts_with("#") { 
                    println!("Color already hex encoded.");
                } else {
                    rule.value = format!("prefixed_{}", rule.value);
                }
            },
            "font-size" => {
                if !rule.value.contains("px") { 
                    rule.value = format!("{}", rule.value);
                }
            },
            _ => {}
        }

        sorted_rules.push(std::mem::replace(rule, CssRule { name: String::new(), value: String::new(), is_sorted: false }));
    }

    sorted_rules
}

use std::collections::HashMap;

struct Particle {
    id: u32,
    lifetime: f32,
    position: (f32, f32),
}

fn process_particles(mut particles: Vec<Particle>) -> HashMap<u32, f32> {
    let mut processed_data: HashMap<u32, f32> = HashMap::new();
    for particle in particles {
        if particle.lifetime > 0.1 {
            let energy_level = particle.position.0 * particle.lifetime + particle.position.1;
            processed_data.insert(particle.id, energy_level);
        }
    }
    processed_data
}

fn main() {
    let initial_particles = vec![ 
        Particle { id: 101, lifetime: 5.0, position: (1.0, 2.0) },
        Particle { id: 102, lifetime: 0.05, position: (3.0, 4.0) },
        Particle { id: 103, lifetime: 1.2, position: (0.5, -1.0) },
    ];
    let results = process_particles(initial_particles);
    println!("Processed particle energy map:");
    for (id, energy) in results { 
        println!("Particle ID: {}, Energy: {:.4}", id, energy);
    }
}

use std::collections::VecDeque;

struct GameState {
    entity_id: u32,
    position: (f32, f32),
}

fn main() {
    let mut recorded_frames: VecDeque<GameState> = VecDeque::new();

    recorded_frames.push_back(GameState { entity_id: 101, position: (1.0, 5.0) });
    recorded_frames.push_back(GameState { entity_id: 202, position: (-3.0, 8.0) });
    recorded_frames.push_back(GameState { entity_id: 303, position: (7.5, -1.2) });

    let mut current_time: f32 = 0.0;

    for frame in recorded_frames.iter() {
        println!("Processing frame for entity {} at time {:.1}", frame.entity_id, current_time);
        if frame.position.0.abs() > 5.0 {
            println!("  Detected large movement step.");
        }
        current_time += 0.033;
    }

    let cleared_count = recorded_frames.pop_front();
    if cleared_count.is_some() {
        println!("Successfully processed and logically 'consumed' the first frame.");
    }
}
